let res = [];
for (const item of $input.all()) {
    // 复制项并添加包装类型
    let itemCopy = {...item.json};
    if (itemCopy.printinfo_type === 1) {
        itemCopy.packaging_type = "彩盒包装";
    } else if (itemCopy.printinfo_type === 2) {
        itemCopy.packaging_type = "整箱包装";
    }
    res.push(itemCopy);
}

return {
  result: res
};
